            .Include(p => p.TreatmentNotes.OrderByDescending(t => t.Date))
            .Include(p => p.Appointments.OrderByDescending(a => a.ScheduledAt))
            .FirstOrDefaultAsync(p => p.Id == id);
    }

    public async Task<Pet> CreateAsync(Pet pet)
    {
        pet.CreatedAt = DateTime.UtcNow;
        db.Pets.Add(pet);
        await db.SaveChangesAsync();
        return pet;
    }

    public async Task UpdateAsync(Pet pet)
    {
        db.Pets.Update(pet);
        await db.SaveChangesAsync();
    }

    public async Task<TreatmentNote> AddTreatmentNoteAsync(TreatmentNote note)
    {
        note.CreatedAt = DateTime.UtcNow;
        db.TreatmentNotes.Add(note);
        await db.SaveChangesAsync();
        return note;
    }

    public async Task<List<Pet>> GetRecentPatientsAsync(int count = 5)
    {
        return await db.Pets.Where(p => p.IsActive)
            .OrderByDescending(p => p.CreatedAt)
            .Take(count)
            .ToListAsync();
    }
}

using Microsoft.EntityFrameworkCore;
using VetClinic.Data;

namespace VetClinic.Services;

public class AppointmentService(ApplicationDbContext db)
{
    public async Task<List<Appointment>> GetAllAsync(AppointmentStatus? status = null)
    {
        var query = db.Appointments.Include(a => a.Pet).AsQueryable();
        if (status.HasValue)
            query = query.Where(a => a.Status == status.Value);
        return await query.OrderBy(a => a.ScheduledAt).ToListAsync();
    }

    public async Task<List<Appointment>> GetForWeekAsync(DateTime weekStart)
    {
        var weekEnd = weekStart.AddDays(7);
        return await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.ScheduledAt >= weekStart && a.ScheduledAt < weekEnd)
            .OrderBy(a => a.ScheduledAt)
            .ToListAsync();
    }

    public async Task<List<Appointment>> GetTodayAsync()
    {
        var today = DateTime.Today;
        var tomorrow = today.AddDays(1);
        return await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.ScheduledAt >= today && a.ScheduledAt < tomorrow)
            .OrderBy(a => a.ScheduledAt)
            .ToListAsync();
    }

    public async Task<Appointment> CreateAsync(Appointment appointment)
    {
        appointment.CreatedAt = DateTime.UtcNow;
        db.Appointments.Add(appointment);
        await db.SaveChangesAsync();
        return appointment;
    }

    public async Task UpdateAsync(Appointment appointment)
    {
        db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
    }

    public async Task RescheduleAsync(int id, DateTime newTime)
    {
        var appointment = await db.Appointments.FindAsync(id);
        if (appointment != null)
        {
            appointment.ScheduledAt = newTime;
            await db.SaveChangesAsync();
        }
    }

    public async Task CancelAsync(int id)
    {
        var appointment = await db.Appointments.FindAsync(id);
        if (appointment != null)
        {
            appointment.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
    }

    public async Task CompleteAsync(int id)
    {
        var appointment = await db.Appointments.FindAsync(id);
        if (appointment != null)
        {
            appointment.Status = AppointmentStatus.Completed;
            await db.SaveChangesAsync();
        }
    }

    public List<DateTime> GetAvailableSlots(DateTime date, List<Appointment> existingAppointments)
    {
        var slots = new List<DateTime>();
        var start = date.Date.AddHours(8); // 8 AM
        var end = date.Date.AddHours(17); // 5 PM

        for (var time = start; time < end; time = time.AddMinutes(30))
        {
            var slotEnd = time.AddMinutes(30);
            var hasConflict = existingAppointments.Any(a =>
                a.Status != AppointmentStatus.Cancelled &&
                a.ScheduledAt < slotEnd &&
                a.ScheduledAt.AddMinutes(a.DurationMinutes) > time);
            if (!hasConflict)
                slots.Add(time);
        }
        return slots;
    }
}

using Microsoft.EntityFrameworkCore;
using VetClinic.Data;

namespace VetClinic.Services;

public class BillingService(ApplicationDbContext db)
{
    public async Task<List<Invoice>> GetAllAsync(InvoiceStatus? status = null)
    {
        var query = db.Invoices.Include(i => i.Pet).Include(i => i.Items).AsQueryable();
        if (status.HasValue)
            query = query.Where(i => i.Status == status.Value);
        return await query.OrderByDescending(i => i.IssuedAt).ToListAsync();
    }

    public async Task<Invoice?> GetByIdAsync(int id)
    {
        return await db.Invoices
            .Include(i => i.Pet)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == id);
    }

    public async Task<Invoice> CreateAsync(Invoice invoice)
    {
        invoice.InvoiceNumber = await GenerateInvoiceNumberAsync();
        invoice.IssuedAt = DateTime.UtcNow;
        if (invoice.DueDate == default)
            invoice.DueDate = DateTime.UtcNow.AddDays(30);
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        return invoice;
    }

    public async Task AddItemAsync(InvoiceItem item)
    {
        db.InvoiceItems.Add(item);
        await db.SaveChangesAsync();
    }

    public async Task RemoveItemAsync(int itemId)
    {
        var item = await db.InvoiceItems.FindAsync(itemId);
        if (item != null)
        {
            db.InvoiceItems.Remove(item);
            await db.SaveChangesAsync();
        }
    }

    public async Task<Payment> ProcessPaymentAsync(Payment payment)
    {
        payment.PaidAt = DateTime.UtcNow;
        db.Payments.Add(payment);

        var invoice = await db.Invoices.Include(i => i.Items).Include(i => i.Payments).FirstOrDefaultAsync(i => i.Id == payment.InvoiceId);
        if (invoice != null)
        {
            var totalPaid = invoice.Payments.Sum(p => p.Amount) + payment.Amount;
            var totalAmount = invoice.Items.Sum(i => i.Quantity * i.UnitPrice);
            if (totalPaid >= totalAmount)
                invoice.Status = InvoiceStatus.Paid;
        }

        await db.SaveChangesAsync();
        return payment;
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync(int? invoiceId = null)
    {
        var query = db.Payments.Include(p => p.Invoice).ThenInclude(i => i.Pet).AsQueryable();
        if (invoiceId.HasValue)
            query = query.Where(p => p.InvoiceId == invoiceId.Value);
        return await query.OrderByDescending(p => p.PaidAt).ToListAsync();
    }

    public async Task<List<Invoice>> GetOverdueInvoicesAsync()
    {
        return await db.Invoices
            .Include(i => i.Pet)
            .Include(i => i.Items)
            .Where(i => i.Status == InvoiceStatus.Pending && i.DueDate < DateTime.UtcNow)
            .OrderBy(i => i.DueDate)
            .ToListAsync();
    }

    public async Task UpdateStatusAsync(int id, InvoiceStatus status)
    {
        var invoice = await db.Invoices.FindAsync(id);
        if (invoice != null)
        {
            invoice.Status = status;
            await db.SaveChangesAsync();
        }
    }

    private async Task<string> GenerateInvoiceNumberAsync()
    {
        var count = await db.Invoices.CountAsync();
        return $"INV-{(count + 1):D4}";
    }
}

