@page "/"
@attribute [Authorize]
@inject VetClinic.Services.PatientService PatientService
@inject VetClinic.Services.AppointmentService AppointmentService
@inject VetClinic.Services.BillingService BillingService

<PageTitle>Dashboard - VetClinic</PageTitle>

<h1 class="mb-4">Dashboard</h1>

<div class="row">
    <div class="col-md-4">
        <div class="card mb-3">
            <div class="card-header bg-primary text-white">
                <h5 class="mb-0">Today's Appointments</h5>
            </div>
            <div class="card-body">
                @if (todayAppointments == null)
                {
                    <p><em>Loading...</em></p>
                }
                else if (!todayAppointments.Any())
                {
                    <p class="text-muted">No appointments today.</p>
                }
                else
                {
                    <ul class="list-group list-group-flush">
                        @foreach (var appt in todayAppointments)
                        {
                            <li class="list-group-item d-flex justify-content-between align-items-center">
                                <div>
                                    <strong>@appt.ScheduledAt.ToString("HH:mm")</strong> — @appt.Pet.Name
                                    <br /><small class="text-muted">@appt.Reason</small>
                                </div>
                                <span class="badge bg-@GetStatusColor(appt.Status)">@appt.Status</span>
                            </li>
                        }
                    </ul>
                }
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card mb-3">
            <div class="card-header bg-success text-white">
                <h5 class="mb-0">Recent Patients</h5>
            </div>
            <div class="card-body">
                @if (recentPatients == null)
                {
                    <p><em>Loading...</em></p>
                }
                else if (!recentPatients.Any())
                {
                    <p class="text-muted">No patients yet.</p>
                }
                else
                {
                    <ul class="list-group list-group-flush">
                        @foreach (var pet in recentPatients)
                        {
                            <li class="list-group-item">
                                <a href="patients/@pet.Id">@pet.Name</a> (@pet.Species)
                                <br /><small class="text-muted">Owner: @pet.OwnerName</small>
                            </li>
                        }
                    </ul>
                }
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card mb-3">
            <div class="card-header bg-warning text-dark">
                <h5 class="mb-0">Overdue Invoices</h5>
            </div>
            <div class="card-body">
                @if (overdueInvoices == null)
                {
                    <p><em>Loading...</em></p>
                }
                else if (!overdueInvoices.Any())
                {
                    <p class="text-muted">No overdue invoices.</p>
                }
                else
                {
                    <ul class="list-group list-group-flush">
                        @foreach (var inv in overdueInvoices)
                        {
                            <li class="list-group-item d-flex justify-content-between">
                                <div>
                                    <a href="billing/@inv.Id">@inv.InvoiceNumber</a>
                                    <br /><small class="text-muted">@inv.Pet.Name — Due: @inv.DueDate.ToString("d")</small>
                                </div>
                                <span class="text-danger fw-bold">@inv.Items.Sum(i => i.Quantity * i.UnitPrice).ToString("C")</span>
                            </li>
                        }
                    </ul>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private List<VetClinic.Data.Appointment>? todayAppointments;
    private List<VetClinic.Data.Pet>? recentPatients;
    private List<VetClinic.Data.Invoice>? overdueInvoices;

    protected override async Task OnInitializedAsync()
    {
        todayAppointments = await AppointmentService.GetTodayAsync();
        recentPatients = await PatientService.GetRecentPatientsAsync();
        overdueInvoices = await BillingService.GetOverdueInvoicesAsync();
    }

    private string GetStatusColor(VetClinic.Data.AppointmentStatus status) => status switch
    {
        VetClinic.Data.AppointmentStatus.Scheduled => "info",
        VetClinic.Data.AppointmentStatus.Completed => "success",
        VetClinic.Data.AppointmentStatus.Cancelled => "secondary",
        _ => "light"
    };
}

@page "/patients/{Id:int}"
@attribute [Authorize]
@inject VetClinic.Services.PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>Patient Details - VetClinic</PageTitle>

@if (pet == null)
{
    <p><em>Loading...</em></p>
}
else
{
    <div class="d-flex justify-content-between align-items-center mb-4">
        <h1>@pet.Name</h1>
        <a href="/patients" class="btn btn-outline-secondary">Back to Patients</a>
    </div>

    <div class="row">
        <div class="col-md-6">
            <div class="card mb-4">
                <div class="card-header d-flex justify-content-between">
                    <h5 class="mb-0">Patient Information</h5>
                    <button class="btn btn-sm btn-outline-primary" @onclick="() => isEditing = !isEditing">
                        @(isEditing ? "Cancel" : "Edit")
                    </button>
                </div>
                <div class="card-body">
                    @if (isEditing)
                    {
                        <EditForm Model="pet" OnValidSubmit="SavePatientAsync" FormName="editPet">
                            <DataAnnotationsValidator />
                            <div class="mb-3">
                                <label class="form-label">Name</label>
                                <InputText class="form-control" @bind-Value="pet.Name" />
                            </div>
                            <div class="mb-3">
                                <label class="form-label">Species</label>
                                <InputSelect class="form-control" @bind-Value="pet.Species">
                                    <option value="Dog">Dog</option>
                                    <option value="Cat">Cat</option>
                                    <option value="Bird">Bird</option>
                                    <option value="Rabbit">Rabbit</option>
                                    <option value="Other">Other</option>
                                </InputSelect>
                            </div>
                            <div class="mb-3">
                                <label class="form-label">Breed</label>
                                <InputText class="form-control" @bind-Value="pet.Breed" />
                            </div>
                            <div class="mb-3">
                                <label class="form-label">Date of Birth</label>
                                <InputDate class="form-control" @bind-Value="pet.DateOfBirth" />
                            </div>
                            <div class="mb-3">
                                <label class="form-label">Weight (kg)</label>
                                <InputNumber class="form-control" @bind-Value="pet.Weight" />
                            </div>
                            <div class="mb-3">
                                <label class="form-label">Owner Name</label>
                                <InputText class="form-control" @bind-Value="pet.OwnerName" />
                            </div>
                            <div class="mb-3">
                                <label class="form-label">Owner Phone</label>
                                <InputText class="form-control" @bind-Value="pet.OwnerPhone" />
                            </div>
                            <div class="mb-3">
                                <label class="form-label">Owner Email</label>
                                <InputText class="form-control" @bind-Value="pet.OwnerEmail" />
                            </div>
                            <div class="mb-3">
                                <label class="form-label">Notes</label>
                                <InputTextArea class="form-control" @bind-Value="pet.Notes" />
                            </div>
                            <button type="submit" class="btn btn-success">Save</button>
                        </EditForm>
                    }
                    else
                    {
                        <dl class="row mb-0">
                            <dt class="col-sm-4">Species</dt>
                            <dd class="col-sm-8">@pet.Species</dd>
                            <dt class="col-sm-4">Breed</dt>
                            <dd class="col-sm-8">@(pet.Breed ?? "—")</dd>
                            <dt class="col-sm-4">Date of Birth</dt>
                            <dd class="col-sm-8">@(pet.DateOfBirth?.ToString("d") ?? "—")</dd>
                            <dt class="col-sm-4">Weight</dt>
                            <dd class="col-sm-8">@(pet.Weight.HasValue ? $"{pet.Weight} kg" : "—")</dd>
                            <dt class="col-sm-4">Owner</dt>
                            <dd class="col-sm-8">@pet.OwnerName</dd>
                            <dt class="col-sm-4">Phone</dt>
                            <dd class="col-sm-8">@pet.OwnerPhone</dd>
                            <dt class="col-sm-4">Email</dt>
                            <dd class="col-sm-8">@(pet.OwnerEmail ?? "—")</dd>
                            <dt class="col-sm-4">Notes</dt>
                            <dd class="col-sm-8">@(pet.Notes ?? "—")</dd>
                            <dt class="col-sm-4">Active</dt>
                            <dd class="col-sm-8">@(pet.IsActive ? "Yes" : "No")</dd>
                        </dl>
                    }
                </div>
            </div>
        </div>

        <div class="col-md-6">
            <div class="card mb-4">
                <div class="card-header d-flex justify-content-between">
                    <h5 class="mb-0">Treatment History</h5>
                    <button class="btn btn-sm btn-success" @onclick="() => showAddTreatment = true">Add Note</button>
                </div>
                <div class="card-body">
                    @if (showAddTreatment)
                    {
                        <EditForm Model="newTreatment" OnValidSubmit="AddTreatmentAsync" FormName="addTreatment" class="mb-3 p-3 border rounded bg-light">
                            <DataAnnotationsValidator />
                            <div class="mb-2">
                                <label class="form-label">Date</label>
                                <InputDate class="form-control" @bind-Value="newTreatment.Date" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Description</label>
                                <InputTextArea class="form-control" @bind-Value="newTreatment.Description" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Diagnosis</label>
                                <InputText class="form-control" @bind-Value="newTreatment.Diagnosis" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Medication</label>
                                <InputText class="form-control" @bind-Value="newTreatment.Medication" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Vet Name</label>
                                <InputText class="form-control" @bind-Value="newTreatment.VetName" />
                            </div>
                            <button type="submit" class="btn btn-success btn-sm me-2">Save</button>
                            <button type="button" class="btn btn-secondary btn-sm" @onclick="() => showAddTreatment = false">Cancel</button>
                        </EditForm>
                    }

                    @if (!pet.TreatmentNotes.Any())
                    {
                        <p class="text-muted">No treatment notes yet.</p>
                    }
                    else
                    {
                        @foreach (var note in pet.TreatmentNotes)
                        {
                            <div class="border-bottom pb-2 mb-2">
                                <div class="d-flex justify-content-between">
                                    <strong>@note.Date.ToString("d")</strong>
                                    <small class="text-muted">Dr. @note.VetName</small>
                                </div>
                                <p class="mb-1">@note.Description</p>
                                @if (!string.IsNullOrEmpty(note.Diagnosis))
                                {
                                    <small><strong>Diagnosis:</strong> @note.Diagnosis</small><br />
                                }
                                @if (!string.IsNullOrEmpty(note.Medication))
                                {
                                    <small><strong>Medication:</strong> @note.Medication</small>
                                }
                            </div>
                        }
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private VetClinic.Data.Pet? pet;
    private bool isEditing;
    private bool showAddTreatment;
    private VetClinic.Data.TreatmentNote newTreatment = new() { Date = DateTime.Today };

    protected override async Task OnInitializedAsync()
    {
        pet = await PatientService.GetByIdAsync(Id);
    }

    private async Task SavePatientAsync()
    {
        if (pet != null)
        {
            await PatientService.UpdateAsync(pet);
            isEditing = false;
        }
    }

    private async Task AddTreatmentAsync()
    {
        newTreatment.PetId = Id;
        await PatientService.AddTreatmentNoteAsync(newTreatment);
        newTreatment = new() { Date = DateTime.Today };
        showAddTreatment = false;
        pet = await PatientService.GetByIdAsync(Id);
    }
}

