@if (invoice == null)
{
    <p><em>Loading...</em></p>
}
else
{
    <div class="d-flex justify-content-between align-items-center mb-4">
        <h1>Invoice @invoice.InvoiceNumber</h1>
        <a href="/billing" class="btn btn-outline-secondary">Back to Billing</a>
    </div>

    <div class="row">
        <div class="col-md-8">
            <div class="card mb-4">
                <div class="card-header d-flex justify-content-between">
                    <h5 class="mb-0">Invoice Details</h5>
                    <span class="badge bg-@GetInvoiceStatusColor(invoice.Status) fs-6">@invoice.Status</span>
                </div>
                <div class="card-body">
                    <dl class="row">
                        <dt class="col-sm-3">Patient</dt>
                        <dd class="col-sm-9"><a href="patients/@invoice.Pet.Id">@invoice.Pet.Name</a></dd>
                        <dt class="col-sm-3">Owner</dt>
                        <dd class="col-sm-9">@invoice.Pet.OwnerName</dd>
                        <dt class="col-sm-3">Issued</dt>
                        <dd class="col-sm-9">@invoice.IssuedAt.ToString("d")</dd>
                        <dt class="col-sm-3">Due Date</dt>
                        <dd class="col-sm-9">@invoice.DueDate.ToString("d")</dd>
                    </dl>

                    <h6 class="mt-4">Line Items</h6>
                    <table class="table table-sm">
                        <thead>
                            <tr>
                                <th>Description</th>
                                <th>Qty</th>
                                <th>Unit Price</th>
                                <th>Amount</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var item in invoice.Items)
                            {
                                <tr>
                                    <td>@item.Description</td>
                                    <td>@item.Quantity</td>
                                    <td>@item.UnitPrice.ToString("C")</td>
                                    <td>@((item.Quantity * item.UnitPrice).ToString("C"))</td>
                                    <td>
                                        @if (invoice.Status == VetClinic.Data.InvoiceStatus.Pending)
                                        {
                                            <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveItemAsync(item.Id)">×</button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                        <tfoot>
                            <tr class="fw-bold">
                                <td colspan="3" class="text-end">Total:</td>
                                <td>@invoice.Items.Sum(i => i.Quantity * i.UnitPrice).ToString("C")</td>
                                <td></td>
                            </tr>
                        </tfoot>
                    </table>

                    @if (invoice.Status == VetClinic.Data.InvoiceStatus.Pending)
                    {
                        <div class="border rounded p-3 bg-light mt-3">
                            <h6>Add Line Item</h6>
                            <EditForm Model="newItem" OnValidSubmit="AddItemAsync" FormName="addItem">
                                <DataAnnotationsValidator />
                                <div class="row g-2 align-items-end">
                                    <div class="col-md-4">
                                        <label class="form-label">Description</label>
                                        <InputText class="form-control form-control-sm" @bind-Value="newItem.Description" />
                                    </div>
                                    <div class="col-md-2">
                                        <label class="form-label">Qty</label>
                                        <InputNumber class="form-control form-control-sm" @bind-Value="newItem.Quantity" />
                                    </div>
                                    <div class="col-md-3">
                                        <label class="form-label">Unit Price</label>
                                        <InputNumber class="form-control form-control-sm" @bind-Value="newItem.UnitPrice" />
                                    </div>
                                    <div class="col-md-3">
                                        <button type="submit" class="btn btn-sm btn-success">Add</button>
                                    </div>
                                </div>
                            </EditForm>
                        </div>
                    }
                </div>
            </div>
        </div>

        <div class="col-md-4">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">Payments</h5></div>
                <div class="card-body">
                    @if (invoice.Payments.Any())
                    {
                        <ul class="list-group list-group-flush mb-3">
                            @foreach (var pmt in invoice.Payments)
                            {
                                <li class="list-group-item">
                                    <div class="d-flex justify-content-between">
                                        <span>@pmt.PaidAt.ToString("d")</span>
                                        <strong>@pmt.Amount.ToString("C")</strong>
                                    </div>
                                    <small class="text-muted">@pmt.Method @(pmt.Reference != null ? $"— {pmt.Reference}" : "")</small>
                                </li>
                            }
                        </ul>
                        <div class="d-flex justify-content-between mb-3">
                            <span>Total Paid:</span>
                            <strong>@invoice.Payments.Sum(p => p.Amount).ToString("C")</strong>
                        </div>
                    }
                    else
                    {
                        <p class="text-muted">No payments recorded.</p>
                    }

                    @if (invoice.Status == VetClinic.Data.InvoiceStatus.Pending || invoice.Status == VetClinic.Data.InvoiceStatus.Overdue)
                    {
                        <hr />
                        <h6>Record Payment</h6>
                        <EditForm Model="newPayment" OnValidSubmit="ProcessPaymentAsync" FormName="processPayment">
                            <DataAnnotationsValidator />
                            <div class="mb-2">
                                <label class="form-label">Amount</label>
                                <InputNumber class="form-control form-control-sm" @bind-Value="newPayment.Amount" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Method</label>
                                <InputSelect class="form-control form-control-sm" @bind-Value="newPayment.Method">
                                    <option value="@VetClinic.Data.PaymentMethod.Cash">Cash</option>
                                    <option value="@VetClinic.Data.PaymentMethod.Card">Card</option>
                                    <option value="@VetClinic.Data.PaymentMethod.BankTransfer">Bank Transfer</option>
                                </InputSelect>
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Reference</label>
                                <InputText class="form-control form-control-sm" @bind-Value="newPayment.Reference" />
                            </div>
                            <button type="submit" class="btn btn-success btn-sm">Record Payment</button>
                        </EditForm>
                    }
                </div>
            </div>

            @if (invoice.Status == VetClinic.Data.InvoiceStatus.Pending)
            {
                <button class="btn btn-outline-danger w-100" @onclick="CancelInvoiceAsync">Cancel Invoice</button>
            }
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private VetClinic.Data.Invoice? invoice;
    private VetClinic.Data.InvoiceItem newItem = new() { Quantity = 1 };
    private VetClinic.Data.Payment newPayment = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoiceAsync();
    }

    private async Task LoadInvoiceAsync()
    {
        invoice = await BillingService.GetByIdAsync(Id);
    }

    private async Task AddItemAsync()
    {
        newItem.InvoiceId = Id;
        await BillingService.AddItemAsync(newItem);
        newItem = new() { Quantity = 1 };
        await LoadInvoiceAsync();
    }

    private async Task RemoveItemAsync(int itemId)
    {
        await BillingService.RemoveItemAsync(itemId);
        await LoadInvoiceAsync();
    }

    private async Task ProcessPaymentAsync()
    {
        newPayment.InvoiceId = Id;
        await BillingService.ProcessPaymentAsync(newPayment);
        newPayment = new();
        await LoadInvoiceAsync();
    }

    private async Task CancelInvoiceAsync()
    {
        await BillingService.UpdateStatusAsync(Id, VetClinic.Data.InvoiceStatus.Cancelled);
        await LoadInvoiceAsync();
    }

    private string GetInvoiceStatusColor(VetClinic.Data.InvoiceStatus status) => status switch
    {
        VetClinic.Data.InvoiceStatus.Pending => "warning",
        VetClinic.Data.InvoiceStatus.Paid => "success",
        VetClinic.Data.InvoiceStatus.Overdue => "danger",
        VetClinic.Data.InvoiceStatus.Cancelled => "secondary",
        _ => "light"
    };
}

@page "/appointments"
@attribute [Authorize]
@inject VetClinic.Services.AppointmentService AppointmentService
@inject VetClinic.Services.PatientService PatientService

<PageTitle>Appointments - VetClinic</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-4">
    <h1>Appointments</h1>
    <button class="btn btn-primary" @onclick="() => showAddForm = true">New Appointment</button>
</div>

<div class="d-flex justify-content-between align-items-center mb-3">
    <div class="btn-group">
        <button class="btn btn-outline-secondary" @onclick="PreviousWeek">&laquo; Previous</button>
        <button class="btn btn-outline-secondary" @onclick="() => weekStart = StartOfWeek(DateTime.Today)">Today</button>
        <button class="btn btn-outline-secondary" @onclick="NextWeek">Next &raquo;</button>
    </div>
    <h5>@weekStart.ToString("MMM d") — @weekStart.AddDays(6).ToString("MMM d, yyyy")</h5>
</div>

@if (showAddForm)
{
    <div class="card mb-4">
        <div class="card-header"><h5>New Appointment</h5></div>
        <div class="card-body">
            <EditForm Model="newAppointment" OnValidSubmit="CreateAppointmentAsync" FormName="addAppt">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />
                <div class="row">
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Patient</label>
                        <InputSelect class="form-control" @bind-Value="newAppointment.PetId">
                            <option value="0">Select patient...</option>
                            @if (allPets != null)
                            {
                                @foreach (var p in allPets)
                                {
                                    <option value="@p.Id">@p.Name (@p.OwnerName)</option>
                                }
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Date & Time</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="newAppointment.ScheduledAt" />
                    </div>
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Duration (minutes)</label>
                        <InputNumber class="form-control" @bind-Value="newAppointment.DurationMinutes" />
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="newAppointment.Reason" />
                    </div>
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Vet Name</label>
                        <InputText class="form-control" @bind-Value="newAppointment.VetName" />
                    </div>
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Notes</label>
                        <InputText class="form-control" @bind-Value="newAppointment.Notes" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success me-2">Create</button>
                <button type="button" class="btn btn-secondary" @onclick="() => showAddForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<div class="table-responsive">
    <table class="table table-bordered">
        <thead class="table-light">
            <tr>
                <th style="width:80px">Time</th>
                @for (int d = 0; d < 7; d++)
                {
                    var day = weekStart.AddDays(d);
                    <th class="@(day.Date == DateTime.Today ? "table-active" : "")">
                        @day.ToString("ddd M/d")
                    </th>
                }
            </tr>
        </thead>
        <tbody>
            @for (int hour = 8; hour < 17; hour++)
            {
                <tr>
                    <td class="text-muted small">@($"{hour:D2}:00")</td>
                    @for (int d = 0; d < 7; d++)
                    {
                        var slotTime = weekStart.AddDays(d).AddHours(hour);
                        var slotAppts = GetAppointmentsForSlot(slotTime);
                        <td class="@(slotTime.Date == DateTime.Today ? "table-active" : "")">
                            @foreach (var appt in slotAppts)
                            {
                                <div class="badge bg-@GetStatusColor(appt.Status) text-wrap mb-1 d-block text-start" style="cursor:pointer"
                                     @onclick="() => SelectAppointment(appt)">
                                    @appt.Pet.Name<br />
                                    <small>@appt.Reason</small>
                                </div>
                            }
                        </td>
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

@if (selectedAppointment != null)
{
    <div class="card mt-3">
        <div class="card-header d-flex justify-content-between">
            <h5>Appointment Details</h5>
            <button class="btn-close" @onclick="() => selectedAppointment = null"></button>
        </div>
        <div class="card-body">
            <dl class="row">
                <dt class="col-sm-3">Patient</dt>
                <dd class="col-sm-9">@selectedAppointment.Pet.Name</dd>
                <dt class="col-sm-3">Date/Time</dt>
                <dd class="col-sm-9">@selectedAppointment.ScheduledAt.ToString("g")</dd>
                <dt class="col-sm-3">Duration</dt>
                <dd class="col-sm-9">@selectedAppointment.DurationMinutes min</dd>
                <dt class="col-sm-3">Reason</dt>
                <dd class="col-sm-9">@selectedAppointment.Reason</dd>
                <dt class="col-sm-3">Vet</dt>
                <dd class="col-sm-9">@selectedAppointment.VetName</dd>
                <dt class="col-sm-3">Status</dt>
                <dd class="col-sm-9"><span class="badge bg-@GetStatusColor(selectedAppointment.Status)">@selectedAppointment.Status</span></dd>
            </dl>
            @if (selectedAppointment.Status == VetClinic.Data.AppointmentStatus.Scheduled)
            {
                <button class="btn btn-success me-2" @onclick="CompleteSelectedAsync">Mark Completed</button>
                <button class="btn btn-danger" @onclick="CancelSelectedAsync">Cancel</button>
            }
        </div>
    </div>
}

@code {
    private DateTime weekStart;
    private List<VetClinic.Data.Appointment> weekAppointments = new();
    private List<VetClinic.Data.Pet>? allPets;
    private bool showAddForm;
    private VetClinic.Data.Appointment newAppointment = new() { ScheduledAt = DateTime.Today.AddHours(9), DurationMinutes = 30 };
    private VetClinic.Data.Appointment? selectedAppointment;

    protected override async Task OnInitializedAsync()
    {
        weekStart = StartOfWeek(DateTime.Today);
        await LoadWeekAsync();
        allPets = await PatientService.GetAllAsync();
    }

    private async Task LoadWeekAsync()
    {
        weekAppointments = await AppointmentService.GetForWeekAsync(weekStart);
    }

    private List<VetClinic.Data.Appointment> GetAppointmentsForSlot(DateTime slotTime)
    {
        return weekAppointments.Where(a =>
            a.ScheduledAt >= slotTime && a.ScheduledAt < slotTime.AddHours(1)).ToList();
    }

    private async Task PreviousWeek() { weekStart = weekStart.AddDays(-7); await LoadWeekAsync(); }
    private async Task NextWeek() { weekStart = weekStart.AddDays(7); await LoadWeekAsync(); }

    private async Task CreateAppointmentAsync()
    {
        if (newAppointment.PetId == 0) return;
        await AppointmentService.CreateAsync(newAppointment);
        newAppointment = new() { ScheduledAt = DateTime.Today.AddHours(9), DurationMinutes = 30 };
        showAddForm = false;
        await LoadWeekAsync();
    }

    private void SelectAppointment(VetClinic.Data.Appointment appt) => selectedAppointment = appt;

    private async Task CompleteSelectedAsync()
    {
        if (selectedAppointment != null)
        {
            await AppointmentService.CompleteAsync(selectedAppointment.Id);
            selectedAppointment = null;
            await LoadWeekAsync();
        }
    }

    private async Task CancelSelectedAsync()
    {
        if (selectedAppointment != null)
        {
            await AppointmentService.CancelAsync(selectedAppointment.Id);
            selectedAppointment = null;
            await LoadWeekAsync();
        }
    }

    private static DateTime StartOfWeek(DateTime date)
    {
        int diff = (7 + (date.DayOfWeek - DayOfWeek.Monday)) % 7;
        return date.AddDays(-diff).Date;
    }

    private string GetStatusColor(VetClinic.Data.AppointmentStatus status) => status switch
    {
        VetClinic.Data.AppointmentStatus.Scheduled => "info",
        VetClinic.Data.AppointmentStatus.Completed => "success",
        VetClinic.Data.AppointmentStatus.Cancelled => "secondary",
        _ => "light"
    };
}

@page "/billing"
@attribute [Authorize]
@inject VetClinic.Services.BillingService BillingService
@inject VetClinic.Services.PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>Billing - VetClinic</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-4">
    <h1>Billing</h1>
    <button class="btn btn-primary" @onclick="() => showCreateForm = true">New Invoice</button>
</div>

<ul class="nav nav-tabs mb-3">
    <li class="nav-item">
        <button class="nav-link @(statusFilter == null ? "active" : "")" @onclick="() => FilterByStatus(null)">All</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(statusFilter == VetClinic.Data.InvoiceStatus.Pending ? "active" : "")" @onclick="() => FilterByStatus(VetClinic.Data.InvoiceStatus.Pending)">Pending</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(statusFilter == VetClinic.Data.InvoiceStatus.Paid ? "active" : "")" @onclick="() => FilterByStatus(VetClinic.Data.InvoiceStatus.Paid)">Paid</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(statusFilter == VetClinic.Data.InvoiceStatus.Overdue ? "active" : "")" @onclick="() => FilterByStatus(VetClinic.Data.InvoiceStatus.Overdue)">Overdue</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(statusFilter == VetClinic.Data.InvoiceStatus.Cancelled ? "active" : "")" @onclick="() => FilterByStatus(VetClinic.Data.InvoiceStatus.Cancelled)">Cancelled</button>
    </li>
</ul>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-header"><h5>Create Invoice</h5></div>
        <div class="card-body">
            <EditForm Model="newInvoice" OnValidSubmit="CreateInvoiceAsync" FormName="createInvoice">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-6 mb-3">
                        <label class="form-label">Patient</label>
                        <InputSelect class="form-control" @bind-Value="newInvoice.PetId">
                            <option value="0">Select patient...</option>
                            @if (allPets != null)
                            {
                                @foreach (var p in allPets)
                                {
                                    <option value="@p.Id">@p.Name (@p.OwnerName)</option>
                                }
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-6 mb-3">
                        <label class="form-label">Due Date</label>
                        <InputDate class="form-control" @bind-Value="newInvoice.DueDate" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success me-2">Create</button>
                <button type="button" class="btn btn-secondary" @onclick="() => showCreateForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (invoices == null)
{
    <p><em>Loading...</em></p>
}
else if (!invoices.Any())
{
    <p class="text-muted">No invoices found.</p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Invoice #</th>
                <th>Patient</th>
                <th>Issued</th>
                <th>Due</th>
                <th>Amount</th>
                <th>Status</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var inv in invoices)
            {
                <tr>
                    <td>@inv.InvoiceNumber</td>
                    <td>@inv.Pet.Name</td>
                    <td>@inv.IssuedAt.ToString("d")</td>
                    <td>@inv.DueDate.ToString("d")</td>
                    <td>@inv.Items.Sum(i => i.Quantity * i.UnitPrice).ToString("C")</td>
                    <td><span class="badge bg-@GetInvoiceStatusColor(inv.Status)">@inv.Status</span></td>
                    <td><a href="billing/@inv.Id" class="btn btn-sm btn-outline-primary">View</a></td>
                </tr>
            }
        </tbody>
    </table>
}

<h3 class="mt-5 mb-3">Recent Payments</h3>
@if (payments == null)
{
    <p><em>Loading...</em></p>
}
else if (!payments.Any())
{
    <p class="text-muted">No payments recorded.</p>
}
else
{
    <table class="table table-sm">
        <thead>
            <tr>
                <th>Date</th>
                <th>Invoice</th>
                <th>Patient</th>
                <th>Amount</th>
                <th>Method</th>
                <th>Reference</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var pmt in payments.Take(10))
            {
                <tr>
                    <td>@pmt.PaidAt.ToString("g")</td>
                    <td>@pmt.Invoice.InvoiceNumber</td>
                    <td>@pmt.Invoice.Pet.Name</td>
                    <td>@pmt.Amount.ToString("C")</td>
                    <td>@pmt.Method</td>
                    <td>@(pmt.Reference ?? "—")</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<VetClinic.Data.Invoice>? invoices;
    private List<VetClinic.Data.Payment>? payments;
    private List<VetClinic.Data.Pet>? allPets;
    private VetClinic.Data.InvoiceStatus? statusFilter;
    private bool showCreateForm;
    private VetClinic.Data.Invoice newInvoice = new() { DueDate = DateTime.Today.AddDays(30) };

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
        allPets = await PatientService.GetAllAsync();
    }

    private async Task LoadDataAsync()
    {
        invoices = await BillingService.GetAllAsync(statusFilter);
        payments = await BillingService.GetPaymentHistoryAsync();
    }

    private async Task FilterByStatus(VetClinic.Data.InvoiceStatus? status)
    {
        statusFilter = status;
        await LoadDataAsync();
    }

    private async Task CreateInvoiceAsync()
    {
        if (newInvoice.PetId == 0) return;
        var created = await BillingService.CreateAsync(newInvoice);
        newInvoice = new() { DueDate = DateTime.Today.AddDays(30) };
        showCreateForm = false;
        Navigation.NavigateTo($"billing/{created.Id}");
    }

    private string GetInvoiceStatusColor(VetClinic.Data.InvoiceStatus status) => status switch
    {
        VetClinic.Data.InvoiceStatus.Pending => "warning",
        VetClinic.Data.InvoiceStatus.Paid => "success",
        VetClinic.Data.InvoiceStatus.Overdue => "danger",
        VetClinic.Data.InvoiceStatus.Cancelled => "secondary",
        _ => "light"
    };
}

@page "/billing/{Id:int}"
