+@page "/appointments"
+@attribute [Authorize]
+@inject VetClinic.Services.AppointmentService AppointmentService
+@inject VetClinic.Services.PatientService PatientService
+
+<PageTitle>Appointments - VetClinic</PageTitle>
+
+<div class="d-flex justify-content-between align-items-center mb-4">
+    <h1>Appointments</h1>
+    <button class="btn btn-primary" @onclick="() => showAddForm = true">New Appointment</button>
+</div>
+
+<div class="d-flex justify-content-between align-items-center mb-3">
+    <div class="btn-group">
+        <button class="btn btn-outline-secondary" @onclick="PreviousWeek">&laquo; Previous</button>
+        <button class="btn btn-outline-secondary" @onclick="() => weekStart = StartOfWeek(DateTime.Today)">Today</button>
+        <button class="btn btn-outline-secondary" @onclick="NextWeek">Next &raquo;</button>
+    </div>
+    <h5>@weekStart.ToString("MMM d") — @weekStart.AddDays(6).ToString("MMM d, yyyy")</h5>
+</div>
+
+@if (showAddForm)
+{
+    <div class="card mb-4">
+        <div class="card-header"><h5>New Appointment</h5></div>
+        <div class="card-body">
+            <EditForm Model="newAppointment" OnValidSubmit="CreateAppointmentAsync" FormName="addAppt">
+                <DataAnnotationsValidator />
+                <ValidationSummary class="text-danger" />
+                <div class="row">
+                    <div class="col-md-4 mb-3">
+                        <label class="form-label">Patient</label>
+                        <InputSelect class="form-control" @bind-Value="newAppointment.PetId">
+                            <option value="0">Select patient...</option>
+                            @if (allPets != null)
+                            {
+                                @foreach (var p in allPets)
+                                {
+                                    <option value="@p.Id">@p.Name (@p.OwnerName)</option>
+                                }
+                            }
+                        </InputSelect>
+                    </div>
+                    <div class="col-md-4 mb-3">
+                        <label class="form-label">Date & Time</label>
+                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="newAppointment.ScheduledAt" />
+                    </div>
+                    <div class="col-md-4 mb-3">
+                        <label class="form-label">Duration (minutes)</label>
+                        <InputNumber class="form-control" @bind-Value="newAppointment.DurationMinutes" />
+                    </div>
+                </div>
+                <div class="row">
+                    <div class="col-md-4 mb-3">
+                        <label class="form-label">Reason</label>
+                        <InputText class="form-control" @bind-Value="newAppointment.Reason" />
+                    </div>
+                    <div class="col-md-4 mb-3">
+                        <label class="form-label">Vet Name</label>
+                        <InputText class="form-control" @bind-Value="newAppointment.VetName" />
+                    </div>
+                    <div class="col-md-4 mb-3">
+                        <label class="form-label">Notes</label>
+                        <InputText class="form-control" @bind-Value="newAppointment.Notes" />
+                    </div>
+                </div>
+                <button type="submit" class="btn btn-success me-2">Create</button>
+                <button type="button" class="btn btn-secondary" @onclick="() => showAddForm = false">Cancel</button>
+            </EditForm>
+        </div>
+    </div>
+}
+
+<div class="table-responsive">
+    <table class="table table-bordered">
+        <thead class="table-light">
+            <tr>
+                <th style="width:80px">Time</th>
+                @for (int d = 0; d < 7; d++)
+                {
+                    var day = weekStart.AddDays(d);
+                    <th class="@(day.Date == DateTime.Today ? "table-active" : "")">
+                        @day.ToString("ddd M/d")
+                    </th>
+                }
+            </tr>
+        </thead>
+        <tbody>
+            @for (int hour = 8; hour < 17; hour++)
+            {
+                <tr>
+                    <td class="text-muted small">@($"{hour:D2}:00")</td>
+                    @for (int d = 0; d < 7; d++)
+                    {
+                        var slotTime = weekStart.AddDays(d).AddHours(hour);
+                        var slotAppts = GetAppointmentsForSlot(slotTime);
+                        <td class="@(slotTime.Date == DateTime.Today ? "table-active" : "")">
+                            @foreach (var appt in slotAppts)
+                            {
+                                <div class="badge bg-@GetStatusColor(appt.Status) text-wrap mb-1 d-block text-start" style="cursor:pointer"
+                                     @onclick="() => SelectAppointment(appt)">
+                                    @appt.Pet.Name<br />
+                                    <small>@appt.Reason</small>
+                                </div>
+                            }
+                        </td>
+                    }
+                </tr>
+            }
+        </tbody>
+    </table>
+</div>
+
+@if (selectedAppointment != null)
+{
+    <div class="card mt-3">
+        <div class="card-header d-flex justify-content-between">
+            <h5>Appointment Details</h5>
+            <button class="btn-close" @onclick="() => selectedAppointment = null"></button>
+        </div>
+        <div class="card-body">
+            <dl class="row">
+                <dt class="col-sm-3">Patient</dt>
+                <dd class="col-sm-9">@selectedAppointment.Pet.Name</dd>
+                <dt class="col-sm-3">Date/Time</dt>
+                <dd class="col-sm-9">@selectedAppointment.ScheduledAt.ToString("g")</dd>
+                <dt class="col-sm-3">Duration</dt>
+                <dd class="col-sm-9">@selectedAppointment.DurationMinutes min</dd>
+                <dt class="col-sm-3">Reason</dt>
+                <dd class="col-sm-9">@selectedAppointment.Reason</dd>
+                <dt class="col-sm-3">Vet</dt>
+                <dd class="col-sm-9">@selectedAppointment.VetName</dd>
+                <dt class="col-sm-3">Status</dt>
+                <dd class="col-sm-9"><span class="badge bg-@GetStatusColor(selectedAppointment.Status)">@selectedAppointment.Status</span></dd>
+            </dl>
+            @if (selectedAppointment.Status == VetClinic.Data.AppointmentStatus.Scheduled)
+            {
+                <button class="btn btn-success me-2" @onclick="CompleteSelectedAsync">Mark Completed</button>
+                <button class="btn btn-danger" @onclick="CancelSelectedAsync">Cancel</button>
+            }
+        </div>
+    </div>
+}
+
+@code {
+    private DateTime weekStart;
+    private List<VetClinic.Data.Appointment> weekAppointments = new();
+    private List<VetClinic.Data.Pet>? allPets;
+    private bool showAddForm;
+    private VetClinic.Data.Appointment newAppointment = new() { ScheduledAt = DateTime.Today.AddHours(9), DurationMinutes = 30 };
+    private VetClinic.Data.Appointment? selectedAppointment;
+
+    protected override async Task OnInitializedAsync()
+    {
+        weekStart = StartOfWeek(DateTime.Today);
+        await LoadWeekAsync();
+        allPets = await PatientService.GetAllAsync();
+    }
+
+    private async Task LoadWeekAsync()
+    {
+        weekAppointments = await AppointmentService.GetForWeekAsync(weekStart);
+    }
+
+    private List<VetClinic.Data.Appointment> GetAppointmentsForSlot(DateTime slotTime)
+    {
+        return weekAppointments.Where(a =>
+            a.ScheduledAt >= slotTime && a.ScheduledAt < slotTime.AddHours(1)).ToList();
+    }
+
+    private async Task PreviousWeek() { weekStart = weekStart.AddDays(-7); await LoadWeekAsync(); }
+    private async Task NextWeek() { weekStart = weekStart.AddDays(7); await LoadWeekAsync(); }
+
+    private async Task CreateAppointmentAsync()
+    {
+        if (newAppointment.PetId == 0) return;
+        await AppointmentService.CreateAsync(newAppointment);
+        newAppointment = new() { ScheduledAt = DateTime.Today.AddHours(9), DurationMinutes = 30 };
+        showAddForm = false;
+        await LoadWeekAsync();
+    }
+
+    private void SelectAppointment(VetClinic.Data.Appointment appt) => selectedAppointment = appt;
+
+    private async Task CompleteSelectedAsync()
+    {
+        if (selectedAppointment != null)
+        {
+            await AppointmentService.CompleteAsync(selectedAppointment.Id);
+            selectedAppointment = null;
+            await LoadWeekAsync();
+        }
+    }
+
+    private async Task CancelSelectedAsync()
+    {
+        if (selectedAppointment != null)
+        {
+            await AppointmentService.CancelAsync(selectedAppointment.Id);
+            selectedAppointment = null;
+            await LoadWeekAsync();
+        }
+    }
+
+    private static DateTime StartOfWeek(DateTime date)
+    {
+        int diff = (7 + (date.DayOfWeek - DayOfWeek.Monday)) % 7;
+        return date.AddDays(-diff).Date;
+    }
+
+    private string GetStatusColor(VetClinic.Data.AppointmentStatus status) => status switch
+    {
+        VetClinic.Data.AppointmentStatus.Scheduled => "info",
+        VetClinic.Data.AppointmentStatus.Completed => "success",
+        VetClinic.Data.AppointmentStatus.Cancelled => "secondary",
+        _ => "light"
+    };
+}
+

